import{_ as o}from"./chunks/shop-manage.CW0LxjuP.js";import{_ as r,o as e,c as a,ae as l}from"./chunks/framework.BzQXgbNp.js";const h=JSON.parse('{"title":"🤖 Minecraft 假人掛機系統 (Carpet Bot)","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Fake-Player.md","filePath":"Mc-Fake-Player.md"}'),n={name:"Mc-Fake-Player.md"};function i(s,t,c,g,d,p){return e(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="🤖-minecraft-假人掛機系統-carpet-bot" tabindex="-1">🤖 Minecraft 假人掛機系統 (Carpet Bot) <a class="header-anchor" href="#🤖-minecraft-假人掛機系統-carpet-bot" aria-label="Permalink to &quot;🤖 Minecraft 假人掛機系統 (Carpet Bot)&quot;">​</a></h1><p>伺服器為所有玩家提供了安全、便捷的假人掛機系統（由 Carpet 模組底層驅動並經過自訂限制），讓您可以在不需要開啟多個 Minecraft 客戶端的情況下，召喚假人登入伺服器掛網、自動刷怪、測試紅石與收集物資。</p><hr><h2 id="⚙️-1-假人基本限制與命名" tabindex="-1">⚙️ 1. 假人基本限制與命名 <a class="header-anchor" href="#⚙️-1-假人基本限制與命名" aria-label="Permalink to &quot;⚙️ 1. 假人基本限制與命名&quot;">​</a></h2><ul><li><strong>名稱前綴自動補全</strong>： <ul><li>當您輸入名稱時，系統會在前方<strong>自動補上 <code>fp_</code></strong>（例如：<code>/fp abc</code> ➡️ 生成假人名稱為 <code>fp_abc</code>）。</li><li>若您輸入的名稱本身即已包含 <code>fp_</code>（不分大小寫，如 <code>fp_rory</code>），系統則會直接使用該名稱，不會重複堆疊。</li><li>假人名稱有效長度限制（包含 <code>fp_</code>）為最長 <strong>16 個字元</strong>。</li></ul></li><li><strong>召喚數量限制</strong>： <ul><li>每位玩家同時只能有 <strong>最多 3 隻</strong> 假人在此線上。</li><li>如果已經有 3 隻您的假人，必須先將其中一隻下線才能再召喚新的假人。</li></ul></li><li><strong>安全性與擁有權保護</strong>： <ul><li>每個假人在首次被召喚時都會自動綁定至該玩家的個人名下。</li><li><strong>非擁有者</strong>（除管理員/OP 外）無法控制、移動或將其他玩家的假人下線，保障物資與掛機位置的安全。</li></ul></li></ul><hr><h2 id="💬-2-遊戲內控制指令" tabindex="-1">💬 2. 遊戲內控制指令 <a class="header-anchor" href="#💬-2-遊戲內控制指令" aria-label="Permalink to &quot;💬 2. 遊戲內控制指令&quot;">​</a></h2><h3 id="召喚與下線-spawn-kill" tabindex="-1">召喚與下線 (Spawn &amp; Kill) <a class="header-anchor" href="#召喚與下線-spawn-kill" aria-label="Permalink to &quot;召喚與下線 (Spawn &amp; Kill)&quot;">​</a></h3><ul><li><strong><code>/fp &lt;名稱&gt;</code></strong> 或 <strong><code>/fp &lt;名稱&gt; spawn</code></strong>：在您當前所站的位置與維度，召喚一個名為 <code>fp_&lt;名稱&gt;</code> 的假人。</li><li><strong><code>/fp &lt;名稱&gt; kill</code></strong>：將您的指定假人安全下線。</li></ul><h3 id="自動化動作-attack-use" tabindex="-1">自動化動作 (Attack &amp; Use) <a class="header-anchor" href="#自動化動作-attack-use" aria-label="Permalink to &quot;自動化動作 (Attack &amp; Use)&quot;">​</a></h3><ul><li><strong><code>/fp &lt;名稱&gt; attack continuous</code></strong>：控制假人<strong>持續左擊</strong>（適用於刷怪塔）。</li><li><strong><code>/fp &lt;名稱&gt; attack interval &lt;ticks&gt;</code></strong>：控制假人每隔指定 ticks（20 ticks = 1 秒）攻擊一次。</li><li><strong><code>/fp &lt;名稱&gt; attack once</code></strong>：控制假人單次攻擊。</li><li><strong><code>/fp &lt;名稱&gt; use continuous</code></strong>：控制假人<strong>持續右擊</strong>（適用於自動種植或餵食）。</li><li><strong><code>/fp &lt;名稱&gt; use interval &lt;ticks&gt;</code></strong>：控制假人每隔指定 ticks 右擊。</li><li><strong><code>/fp &lt;名稱&gt; stop</code></strong>：<strong>停止</strong>假人正在執行的所有自動化動作與移動。</li></ul><h3 id="移動與姿態" tabindex="-1">移動與姿態 <a class="header-anchor" href="#移動與姿態" aria-label="Permalink to &quot;移動與姿態&quot;">​</a></h3><ul><li><strong><code>/fp &lt;名稱&gt; jump</code></strong>：使假人跳躍一次。</li><li><strong><code>/fp &lt;名稱&gt; sneak</code></strong>：使假人保持<strong>蹲下</strong>姿勢。</li><li><strong><code>/fp &lt;名稱&gt; unsneak</code></strong>：使假人取消蹲下。</li><li><strong><code>/fp &lt;名稱&gt; sprint</code></strong>：使假人進入疾跑。</li><li><strong><code>/fp &lt;名稱&gt; unsprint</code></strong>：使假人停止疾跑。</li></ul><h3 id="物品操作" tabindex="-1">物品操作 <a class="header-anchor" href="#物品操作" aria-label="Permalink to &quot;物品操作&quot;">​</a></h3><ul><li><strong><code>/fp &lt;名稱&gt; drop</code></strong>：使假人丟棄主手握著的單個物品。</li><li><strong><code>/fp &lt;名稱&gt; dropStack</code></strong>：使假人丟棄主手握著的整疊物品。</li><li><strong><code>/fp &lt;名稱&gt; swapHands</code></strong>：使假人交換主手與副手物品。</li></ul><hr><h2 id="🖥️-3-網頁端遠端控制面板" tabindex="-1">🖥️ 3. 網頁端遠端控制面板 <a class="header-anchor" href="#🖥️-3-網頁端遠端控制面板" aria-label="Permalink to &quot;🖥️ 3. 網頁端遠端控制面板&quot;">​</a></h2><p>您也可以在網頁端儀表板的 <strong>「假人控制」</strong> 分頁中遠端管理您名下的假人：</p><ol><li><strong>即時名冊</strong>：顯示您擁有的假人狀態、名稱與是否在線。</li><li><strong>一鍵召喚</strong>：在輸入框輸入名稱並點選「召喚假人」即可將其召喚上線（<strong>⚠️ 注意</strong>：您本人必須先在遊戲內線上，假人才能降生在您的位置）。</li><li><strong>快捷按鈕</strong>：對於在線的假人，提供連續攻擊、右擊使用、停止、跳躍、蹲下、換手等全套控制按鈕，免去在遊戲中手動輸入繁瑣命令！</li></ol><p><img src="'+o+'" alt="網頁假人管理面板"></p>',20)])])}const k=r(n,[["render",i]]);export{h as __pageData,k as default};
